frappe.ui.form.on('Employee Advance', {
    custom_advance_type: function(frm) {
        if (!frm.doc.company) {
            frappe.msgprint(__('Please select a Company first.'));
            return;
        }

        frappe.db.get_doc('Company', frm.doc.company)
            .then(company => {
                 if (frm.doc.custom_advance_type === 'For Employee Advance') {
                    frm.set_value('advance_account', company.default_employee_advance_account);
                }
                else if (frm.doc.custom_advance_type === 'For Purchase') {
                    frm.set_value('advance_account', company.custom_default_account_for_purchaser_advance);
                } else if (frm.doc.custom_advance_type === 'For Petty Cash') {
                    frm.set_value('advance_account', company.custom_default_petty_cash_account);
                } else if (frm.doc.custom_advance_type === 'For Service') {
                    frm.set_value('advance_account', company.custom_default_account_for_service_advance);
                }
            })
            .catch(err => {
                console.error(err);
                frappe.msgprint(__('Failed to fetch company data'));
            });
    }
});

frappe.ui.form.on('Interview', {
    job_applicant: function(frm) {
        if (frm.doc.job_applicant) {
            frappe.call({
                method: "customized_forcommon.common_customization.doctype.applicant_test_result.applicant_test_result.get_applicant_test_scores",
                args: {
                    job_applicant: frm.doc.job_applicant
                },
                callback: function(r) {
                    if (r.message && r.message.length > 0) {
                        let result = r.message[0];
                        frm.set_value('custom_written_test_score', result.written_test_score);
                        frm.set_value('custom_practical_test_score', result.practical_test_score);
                    }
                }
            });
        }
    }
});

frappe.ui.form.on('BOM Item', {
    custom_density: function (frm, cdt, cdn) {
        set_density_value(cdt, cdn);
        calculate_quantity(cdt, cdn);
    },
    custom_shape: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_length: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_width: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_height: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_diameter: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_outer_diameter: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_inner_diameter: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_number_of_sides: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    },
    custom_density_value: function (frm, cdt, cdn) {
        calculate_quantity(cdt, cdn);
    }
});


// Set density value based on selected material
function set_density_value(cdt, cdn) {
    let row = locals[cdt][cdn];
    const density_values = {
        "Aluminum": 2.70,
        "Brass": 8.50,
        "Bronze": 8.80,
        "Copper": 8.96,
        "Gold": 19.32,
        "Iron": 7.87,
        "Lead": 11.34,
        "Nickel": 8.90,
        "Platinum": 21.45,
        "Silver": 10.49,
        "Stainless Steel": 8.00,
        "Steel (Carbon)": 7.85,
        "Titanium": 4.51,
        "Zinc": 7.14
    };

    if (row.custom_density in density_values) {
        frappe.model.set_value(cdt, cdn, 'custom_density_value', density_values[row.custom_density]);
    }
}

// Calculate quantity based on shape and dimensions
function calculate_quantity(cdt, cdn) {
    let row = locals[cdt][cdn];

    let qty = 1;
    let density = parseFloat(row.custom_density_value || 0); // in kg/m³
    if (!density || !row.custom_shape) return;

    // Dimensions in mm, convert to meters
    let length = parseFloat(row.custom_length || 0) / 1000;
    let width = parseFloat(row.custom_width || 0) / 1000;
    let height = parseFloat(row.custom_height || 0) / 1000;

    if (row.custom_shape === "Rectangle") {
        let volume_m3 = length * width * height;
        qty = volume_m3 * density;
    }
    else if (row.custom_shape === "Circular") {
        let diameter = parseFloat(row.custom_diameter || 0) / 1000;
        let radius = diameter / 2;
        let volume_m3 = Math.PI * Math.pow(radius, 2) * length;
        qty = volume_m3 * density;
    }
    else if (row.custom_shape === "Tube") {
        let outer_d = parseFloat(row.custom_outer_diameter || 0) / 1000;
        let inner_d = parseFloat(row.custom_inner_diameter || 0) / 1000;
        let volume_m3 = (Math.PI / 4) * (Math.pow(outer_d, 2) - Math.pow(inner_d, 2)) * length;
        qty = volume_m3 * density;
    }
    else if (row.custom_shape === "Polygon") {
        let n_sides = parseInt(row.custom_number_of_sides || 0);
        let side_length = parseFloat(row.custom_width || 0) / 1000;
        let area = (n_sides * Math.pow(side_length, 2)) / (4 * Math.tan(Math.PI / n_sides));
        let volume_m3 = area * length;
        qty = volume_m3 * density;
    }

    frappe.model.set_value(cdt, cdn, 'qty', Math.floor(qty));
}



